import java.util.*;

class BadConfig {
    private List<String> settings;
    BadConfig(List<String> s) { this.settings = s; }  // no copy!
    List<String> getSettings() { return settings; }
}

class GoodConfig {
    private final List<String> settings;
    GoodConfig(List<String> s) { this.settings = new ArrayList<>(s); }  // defensive copy
    List<String> getSettings() { return Collections.unmodifiableList(settings); }
}

public class App {
    public static void main(String[] args) {
        List<String> original = new ArrayList<>(Arrays.asList("A", "B"));

        BadConfig bad = new BadConfig(original);
        original.add("HACKED");  // mutates bad's settings too!
        System.out.println("Without copy — corrupted: " + bad.getSettings());

        original.remove("HACKED");  // restore
        GoodConfig good = new GoodConfig(original);
        original.add("HACKED");  // good is protected
        System.out.println("With copy — protected: " + good.getSettings());
    }
}

import java.util.*;

class Playlist {
    private final String name;
    private final List<String> songs;

    Playlist(String name, List<String> songs) {
        this.name  = Objects.requireNonNull(name, "name required");
        if (name.isBlank()) throw new IllegalArgumentException("name cannot be blank");
        Objects.requireNonNull(songs, "songs required");
        this.songs = new ArrayList<>(songs);  // defensive copy
    }

    String getName() { return name; }
    List<String> getSongs() { return Collections.unmodifiableList(songs); }

    @Override public String toString() {
        return "Playlist '" + name + "' with " + songs.size() + " songs";
    }
}

public class App {
    public static void main(String[] args) {
        List<String> tracks = new ArrayList<>(Arrays.asList("Bohemian Rhapsody", "Stairway to Heaven"));
        Playlist pl = new Playlist("Rock Hits", tracks);
        System.out.println(pl);

        tracks.add("HACKED");  // doesn't affect Playlist

        try {
            pl.getSongs().add("hacked via getter");
        } catch (UnsupportedOperationException e) {
            System.out.println("Cannot modify: yes");
        }
    }
}

