        System.out.println(createLoan("Aisha", 100000, 8.5, 24));
        try { createLoan("Raj", 50000, 150, 12); } 
        catch (IllegalArgumentException e) { System.out.println("Error: " + e.getMessage()); }
        try { createLoan("", 50000, 8.5, 12); } 
        catch (IllegalArgumentException e) { System.out.println("Error: " + e.getMessage()); }
    }
}

import java.util.Objects;

final class Money {
    private final double amount;
    private final String currency;

    Money(double amount, String currency) {
        if (amount < 0) throw new IllegalArgumentException("amount cannot be negative: " + amount);
        this.currency = Objects.requireNonNull(currency, "currency required");
        if (currency.isBlank()) throw new IllegalArgumentException("currency cannot be blank");
        this.amount = amount;
    }

    double getAmount() { return amount; }
    String getCurrency() { return currency; }

    Money add(Money other) {
        Objects.requireNonNull(other, "other required");
        if (!this.currency.equals(other.currency))
            throw new IllegalArgumentException("Cannot add different currencies: " + currency + " vs " + other.currency);
        return new Money(this.amount + other.amount, this.currency);
    }

    Money subtract(Money other) {
        Objects.requireNonNull(other, "other required");
        if (!this.currency.equals(other.currency))
            throw new IllegalArgumentException("Cannot subtract different currencies");
        if (other.amount > this.amount)
            throw new IllegalArgumentException("Result would be negative");
        return new Money(this.amount - other.amount, this.currency);
    }

    @Override public String toString() {
        return String.format("₹%.2f %s", amount, currency);
    }
}

public class App {
    public static void main(String[] args) {
        Money price  = new Money(500, "INR");
        Money wallet = new Money(1000, "INR");

        System.out.println(price);
        System.out.println(price.add(wallet));
        System.out.println(wallet.subtract(price).subtract(new Money(200, "INR")));
    }
}

import java.util.*;

public class App {
    static Optional<String> findEmployee(Map<String, String> employees, String id) {
        Objects.requireNonNull(id, "id required");
        return Optional.ofNullable(employees.get(id));
    }

    public static void main(String[] args) {
        Map<String, String> employees = new HashMap<>();
        employees.put("E001", "Aisha Khan");
        employees.put("E002", "Raj Patel");

        Optional<String> found = findEmployee(employees, "E001");
        System.out.println("Found: " + found.orElse("No employee"));

        Optional<String> missing = findEmployee(employees, "E999");
        System.out.println("Not found: " + missing.orElse("No employee"));

        // map() transforms the value if present
        String email = findEmployee(employees, "E001")
            .map(name -> name.toLowerCase().replace(" ", ".") + "@company.com")
            .orElse("unknown@company.com");
        System.out.println("Email: " + email);
    }
}

