import java.util.*;

public class App {
    static String formatSection(String section) {
        // Private — trusts caller. No null check.
        return "• " + section.toUpperCase();
    }

    static String generateReport(String title, List<String> sections) {
        // Public boundary — validate everything
        Objects.requireNonNull(title, "title required");
        if (title.isBlank()) throw new IllegalArgumentException("title required");
        Objects.requireNonNull(sections, "sections required");
        if (sections.isEmpty()) throw new IllegalArgumentException("sections cannot be empty");

        StringBuilder sb = new StringBuilder("=== " + title + " ===\n");
        for (String s : sections) sb.append(formatSection(s)).append("\n");
        return sb.toString().trim();
    }

    public static void main(String[] args) {
        System.out.println(generateReport("Sales Q1", Arrays.asList("Revenue", "Expenses")));

        try { generateReport("", Arrays.asList("A")); }
        catch (IllegalArgumentException e) { System.out.println("Error: " + e.getMessage()); }

        try { generateReport("Test", new ArrayList<>()); }
        catch (IllegalArgumentException e) { System.out.println("Error: " + e.getMessage()); }
    }
}

import java.util.*;

class UserProfile {
    private final String name;
    private final String email;
    private final int age;
    private final List<String> interests;

    UserProfile(String name, String email, int age, List<String> interests) {
        this.name  = Objects.requireNonNull(name, "name required");
        if (name.isBlank())  throw new IllegalArgumentException("name cannot be blank");
        this.email = Objects.requireNonNull(email, "email required");
        if (!email.contains("@")) throw new IllegalArgumentException("email must contain @");
        if (age < 13 || age > 120) throw new IllegalArgumentException("age must be 13-120, got: " + age);
        this.age = age;
        this.interests = new ArrayList<>(Objects.requireNonNull(interests, "interests required"));
    }

    void addInterest(String interest) {
        Objects.requireNonNull(interest, "interest required");
        if (interest.isBlank()) throw new IllegalArgumentException("interest cannot be blank");
        interests.add(interest);
    }

    List<String> getInterests() { return Collections.unmodifiableList(interests); }

    @Override public String toString() {
        return "Profile: " + name + " (" + age + ") " + email;
    }
}

public class App {
    public static void main(String[] args) {
        List<String> interests = new ArrayList<>(Arrays.asList("coding", "reading"));
        UserProfile p = new UserProfile("Aisha", "aisha@test.com", 28, interests);
        interests.add("HACKED");  // doesn't affect profile
        System.out.println(p);
        System.out.println("Interests: " + p.getInterests());

