import java.util.*;

class ProductCatalog {
    private final Map<String, double[]> catalog = new LinkedHashMap<>();
    // double[]: [0]=price. String: name. Using Map<sku, {name, price}> parallel maps for simplicity.
    private final Map<String, String>  names  = new LinkedHashMap<>();
    private final Map<String, Double>  prices = new LinkedHashMap<>();

    void addProduct(String sku, String name, double price) {
        Objects.requireNonNull(sku,  "sku required");
        Objects.requireNonNull(name, "name required");
        if (sku.isBlank())  throw new IllegalArgumentException("sku cannot be blank");
        if (name.isBlank()) throw new IllegalArgumentException("name cannot be blank");
        if (price <= 0)     throw new IllegalArgumentException("price must be positive, got: " + price);
        if (prices.containsKey(sku)) throw new IllegalArgumentException("SKU already exists: " + sku);
        names.put(sku, name);
        prices.put(sku, price);
        System.out.println("Added: " + sku + " " + name + " ₹" + price);
    }

    void updatePrice(String sku, double newPrice) {
        Objects.requireNonNull(sku, "sku required");
        if (!prices.containsKey(sku)) throw new IllegalArgumentException("SKU not found: " + sku);
        if (newPrice <= 0) throw new IllegalArgumentException("price must be positive, got: " + newPrice);
        prices.put(sku, newPrice);
        System.out.println("Updated " + sku + " → ₹" + newPrice);
    }

    List<String> productsUnder(double maxPrice) {
        List<String> result = new ArrayList<>();
        for (String sku : prices.keySet()) {
            if (prices.get(sku) <= maxPrice) {
                result.add(sku + ": ₹" + prices.get(sku));
            }
        }
        return Collections.unmodifiableList(result);
    }
}

public class App {
    public static void main(String[] args) {
        ProductCatalog cat = new ProductCatalog();
        cat.addProduct("MOUSE-01", "Mouse", 599);
        cat.addProduct("KB-01", "Keyboard", 1999);
        cat.updatePrice("MOUSE-01", 549);

        try { cat.addProduct("MOUSE-01", "Mouse2", 699); }
        catch (IllegalArgumentException e) { System.out.println("Error: " + e.getMessage()); }

        try { cat.updatePrice("GHOST-99", 100); }
        catch (IllegalArgumentException e) { System.out.println("Error: " + e.getMessage()); }

        System.out.println("Under ₹1000: " + cat.productsUnder(1000));
    }
}

record Transaction(String fromAccountId, String toAccountId, double amount, String description) {}

record ValidationResult(boolean valid, String error) {
    static ValidationResult ok() { return new ValidationResult(true, null); }
    static ValidationResult fail(String error) { return new ValidationResult(false, error); }
    public String toString() { return valid ? "valid=true" : "valid=false error=" + error; }
}

class TransactionValidator {
    static ValidationResult validate(Transaction t) {
        if (t == null) return ValidationResult.fail("transaction required");
        if (t.fromAccountId() == null || t.fromAccountId().isBlank())
            return ValidationResult.fail("fromAccountId required");
        if (t.toAccountId() == null || t.toAccountId().isBlank())
            return ValidationResult.fail("toAccountId required");
        if (t.fromAccountId().equals(t.toAccountId()))
            return ValidationResult.fail("cannot transfer to same account");
        if (t.amount() < 1.0 || t.amount() > 1_000_000)
            return ValidationResult.fail("amount must be 1.0-1000000.0, got: " + t.amount());
        if (t.description() != null && t.description().length() > 200)
            return ValidationResult.fail("description too long (max 200)");
        return ValidationResult.ok();
    }
}

public class App {
    public static void main(String[] args) {
        System.out.println(TransactionValidator.validate(new Transaction("A1", "A2", 5000, "payment")));
        System.out.println(TransactionValidator.validate(new Transaction("", "A2", 5000, "")));
        System.out.println(TransactionValidator.validate(new Transaction("A1", "A1", 5000, "")));
        System.out.println(TransactionValidator.validate(new Transaction("A1", "A2", 0.5, "")));
    }
}

import java.util.*;

class AuditedPaymentService {
    private final String serviceName;
    private final Set<String> allowedCurrencies;
    private final List<String> history = new ArrayList<>();

    AuditedPaymentService(String serviceName, Set<String> allowedCurrencies) {
        this.serviceName = Objects.requireNonNull(serviceName, "serviceName required");
        if (serviceName.isBlank()) throw new IllegalArgumentException("serviceName cannot be blank");
        this.allowedCurrencies = new HashSet<>(Objects.requireNonNull(allowedCurrencies, "currencies required"));
    }

    void transfer(String from, String to, double amount, String currency) {
        Objects.requireNonNull(from,     "from required");
        Objects.requireNonNull(to,       "to required");
        Objects.requireNonNull(currency, "currency required");
        if (from.isBlank()) throw new IllegalArgumentException("from cannot be blank");
        if (to.isBlank())   throw new IllegalArgumentException("to cannot be blank");
        if (from.equals(to))     throw new IllegalArgumentException("cannot transfer to same account");
        if (amount <= 0)         throw new IllegalArgumentException("amount must be positive, got: " + amount);
        if (!allowedCurrencies.contains(currency))
            throw new IllegalArgumentException("currency not supported: " + currency);
        String record = from + "→" + to + " ₹" + amount + " " + currency;
        history.add(record);
        System.out.println("Transfer complete: " + record);
    }

    List<String> getTransactionHistory() { return Collections.unmodifiableList(history); }
    Set<String> getAllowedCurrencies() { return Collections.unmodifiableSet(allowedCurrencies); }

    Optional<String> findLastTransfer(String accountId) {
        Objects.requireNonNull(accountId, "accountId required");
        for (int i = history.size() - 1; i >= 0; i--) {
            if (history.get(i).startsWith(accountId)) return Optional.of(history.get(i));
        }
        return Optional.empty();
    }
}

public class App {
    public static void main(String[] args) {
        Set<String> currencies = new HashSet<>(Arrays.asList("INR", "SGD"));
        AuditedPaymentService svc = new AuditedPaymentService("RazorpayService", currencies);
        currencies.add("USD");  // external mutation — doesn't affect service!

        svc.transfer("A001", "A002", 5000, "INR");

        try { svc.transfer("A001", "A002", 100, "USD"); }
        catch (IllegalArgumentException e) { System.out.println("Error: " + e.getMessage()); }

        try { svc.transfer("A001", "A001", 100, "INR"); }
        catch (IllegalArgumentException e) { System.out.println("Error: " + e.getMessage()); }

        List<String> sorted = new ArrayList<>(svc.getAllowedCurrencies());
        Collections.sort(sorted);
        System.out.println("Allowed: " + sorted);

        System.out.println("Last for A001: " + svc.findLastTransfer("A001").orElse("none"));
    }
}
